#include "interface.h"

#include <cstdint>
#include <vector>

uint64_t run_length_sum(
    const std::vector<uint32_t>& values,
    const std::vector<uint16_t>& lengths,
    int iters) {
  const std::size_t n = values.size();
  if (n == 0) {
    return 0;
  }

  const uint32_t* __restrict__ v = values.data();
  const uint16_t* __restrict__ l = lengths.data();

  uint64_t sum = 0;

  for (int iter = 0; iter < iters; ++iter) {
    uint64_t s0 = 0, s1 = 0, s2 = 0, s3 = 0;
    std::size_t i = 0;
    const std::size_t limit = n - (n % 4);

    for (; i < limit; i += 4) {
      s0 += static_cast<uint64_t>(v[i])     * static_cast<uint64_t>(l[i]);
      s1 += static_cast<uint64_t>(v[i + 1]) * static_cast<uint64_t>(l[i + 1]);
      s2 += static_cast<uint64_t>(v[i + 2]) * static_cast<uint64_t>(l[i + 2]);
      s3 += static_cast<uint64_t>(v[i + 3]) * static_cast<uint64_t>(l[i + 3]);
    }

    for (; i < n; ++i) {
      s0 += static_cast<uint64_t>(v[i]) * static_cast<uint64_t>(l[i]);
    }

    sum = s0 + s1 + s2 + s3;
  }

  return sum;
}
